import{_ as s,o as n,c as e,a4 as t}from"./chunks/framework._in6GHBg.js";const g=JSON.parse('{"title":"磁场粒子套路","description":"","frontmatter":{},"headers":[],"relativePath":"physics/routine-magnetic.md","filePath":"physics/routine-magnetic.md"}'),p={name:"physics/routine-magnetic.md"};function l(i,a,o,r,c,d){return n(),e("div",null,[...a[0]||(a[0]=[t(`<h1 id="磁场粒子套路" tabindex="-1">磁场粒子套路 <a class="header-anchor" href="#磁场粒子套路" aria-label="Permalink to &quot;磁场粒子套路&quot;">​</a></h1><p><strong>模型编号</strong>: 22<br><strong>难度</strong>: ⭐⭐⭐⭐<br><strong>核心</strong>: 几何分析 + 圆周运动轨迹</p><hr><h2 id="模型识别" tabindex="-1">模型识别 <a class="header-anchor" href="#模型识别" aria-label="Permalink to &quot;模型识别&quot;">​</a></h2><p><strong>关键词</strong>: 带电粒子、磁场、圆周运动、半径、圆心角、偏转</p><p><strong>常见情境</strong>:</p><ul><li>粒子垂直射入匀强磁场</li><li>直线边界磁场进出</li><li>圆形磁场区域</li><li>临界问题（刚好射出/不射出）</li></ul><hr><h2 id="核心公式" tabindex="-1">核心公式 <a class="header-anchor" href="#核心公式" aria-label="Permalink to &quot;核心公式&quot;">​</a></h2><p><strong>洛伦兹力提供向心力</strong>:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>qvB = mv²/r</span></span>
<span class="line"><span></span></span>
<span class="line"><span>半径：r = mv/qB</span></span>
<span class="line"><span>周期：T = 2πm/qB（与速度无关！）</span></span>
<span class="line"><span>运动时间：t = θm/qB（θ为圆心角，弧度）</span></span></code></pre></div><p><strong>重要特点</strong>: 洛伦兹力不做功，只改变速度方向</p><hr><h2 id="几何分析步骤" tabindex="-1">几何分析步骤 <a class="header-anchor" href="#几何分析步骤" aria-label="Permalink to &quot;几何分析步骤&quot;">​</a></h2><h3 id="步骤1-找圆心" tabindex="-1">步骤1：找圆心 <a class="header-anchor" href="#步骤1-找圆心" aria-label="Permalink to &quot;步骤1：找圆心&quot;">​</a></h3><p><strong>方法1</strong>：速度垂线交点</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>入射速度垂线 + 出射速度垂线 → 交点为圆心</span></span></code></pre></div><p><strong>方法2</strong>：弦的垂直平分线</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>入射点和出射点连线（弦）</span></span>
<span class="line"><span>作弦的垂直平分线 → 过圆心</span></span></code></pre></div><p><strong>方法3</strong>：半径相等</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>圆心到入射点距离 = 圆心到出射点距离 = r</span></span></code></pre></div><h3 id="步骤2-确定半径" tabindex="-1">步骤2：确定半径 <a class="header-anchor" href="#步骤2-确定半径" aria-label="Permalink to &quot;步骤2：确定半径&quot;">​</a></h3><p><strong>已知条件求半径</strong>:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>r = mv/qB</span></span>
<span class="line"><span></span></span>
<span class="line"><span>若不知道v，可通过几何关系求r</span></span></code></pre></div><p><strong>常用几何关系</strong>:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>弦长：L = 2r·sin(θ/2)</span></span>
<span class="line"><span>弧长：s = rθ</span></span>
<span class="line"><span>弦心距：d = r·cos(θ/2)</span></span></code></pre></div><h3 id="步骤3-找圆心角" tabindex="-1">步骤3：找圆心角 <a class="header-anchor" href="#步骤3-找圆心角" aria-label="Permalink to &quot;步骤3：找圆心角&quot;">​</a></h3><p><strong>圆心角与偏转角关系</strong>:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>偏转角（速度转向角）= 圆心角 θ</span></span></code></pre></div><p><strong>直线边界</strong>:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>入射角 = 出射角（对称）</span></span>
<span class="line"><span>偏转角 = 2×入射角</span></span></code></pre></div><h3 id="步骤4-计算时间" tabindex="-1">步骤4：计算时间 <a class="header-anchor" href="#步骤4-计算时间" aria-label="Permalink to &quot;步骤4：计算时间&quot;">​</a></h3><p><strong>运动时间</strong>:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>t = θm/qB</span></span>
<span class="line"><span></span></span>
<span class="line"><span>或：t = (θ/2π)·T = θm/qB（弧度制）</span></span></code></pre></div><p><strong>注意</strong>：θ必须用弧度！</p><hr><h2 id="典型边界问题" tabindex="-1">典型边界问题 <a class="header-anchor" href="#典型边界问题" aria-label="Permalink to &quot;典型边界问题&quot;">​</a></h2><h3 id="类型1-直线边界" tabindex="-1">类型1：直线边界 <a class="header-anchor" href="#类型1-直线边界" aria-label="Permalink to &quot;类型1：直线边界&quot;">​</a></h3><p><strong>特点</strong>：入射角 = 出射角</p><p><strong>几何关系</strong>:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>偏转角 = 2α（α为入射角）</span></span>
<span class="line"><span>侧移距离：d = 2r·sinα·cosα = r·sin(2α)</span></span></code></pre></div><p><strong>时间</strong>:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>t = 2αm/qB（α为弧度）</span></span></code></pre></div><h3 id="类型2-圆形磁场区域" tabindex="-1">类型2：圆形磁场区域 <a class="header-anchor" href="#类型2-圆形磁场区域" aria-label="Permalink to &quot;类型2：圆形磁场区域&quot;">​</a></h3><p><strong>特点</strong>：</p><ul><li>指向圆心入射，背离圆心出射</li><li>四边形：入射点、出射点、磁场圆心、轨迹圆心</li></ul><p><strong>几何关系</strong>:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>设磁场圆半径为R，轨迹半径为r</span></span>
<span class="line"><span>圆心角θ与磁场圆的关系：</span></span>
<span class="line"><span>tan(θ/2) = R/r</span></span>
<span class="line"><span></span></span>
<span class="line"><span>或：sin(θ/2) = R/√(R²+r²)</span></span></code></pre></div><p><strong>偏转角</strong>:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>若粒子指向磁场圆心入射，则偏转角 = 2arctan(R/r)</span></span></code></pre></div><h3 id="类型3-临界问题" tabindex="-1">类型3：临界问题 <a class="header-anchor" href="#类型3-临界问题" aria-label="Permalink to &quot;类型3：临界问题&quot;">​</a></h3><p><strong>问题</strong>：粒子刚好不射出磁场/刚好射出</p><p><strong>解法</strong>：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>找与边界相切的临界轨迹</span></span>
<span class="line"><span></span></span>
<span class="line"><span>相切条件：圆心到边界距离 = r</span></span>
<span class="line"><span></span></span>
<span class="line"><span>可求：临界速度、临界入射角、磁场最小半径等</span></span></code></pre></div><hr><h2 id="典型问题类型" tabindex="-1">典型问题类型 <a class="header-anchor" href="#典型问题类型" aria-label="Permalink to &quot;典型问题类型&quot;">​</a></h2><h3 id="类型1-求半径和圆心角" tabindex="-1">类型1：求半径和圆心角 <a class="header-anchor" href="#类型1-求半径和圆心角" aria-label="Permalink to &quot;类型1：求半径和圆心角&quot;">​</a></h3><p><strong>问题</strong>：粒子以v垂直射入宽度为d的磁场，偏转角度为θ，求r和B</p><p><strong>解法</strong>:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>几何关系：</span></span>
<span class="line"><span>sinθ = d/r（若从对边射出）</span></span>
<span class="line"><span>或：tan(θ/2) = d/r（特定几何）</span></span>
<span class="line"><span></span></span>
<span class="line"><span>由r = mv/qB求B：</span></span>
<span class="line"><span>B = mv/qr</span></span></code></pre></div><h3 id="类型2-求运动时间" tabindex="-1">类型2：求运动时间 <a class="header-anchor" href="#类型2-求运动时间" aria-label="Permalink to &quot;类型2：求运动时间&quot;">​</a></h3><p><strong>问题</strong>：粒子在磁场中运动，圆心角为60°，求时间</p><p><strong>解法</strong>:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>t = θm/qB = (π/3)m/qB = πm/(3qB)</span></span></code></pre></div><h3 id="类型3-多次进出磁场" tabindex="-1">类型3：多次进出磁场 <a class="header-anchor" href="#类型3-多次进出磁场" aria-label="Permalink to &quot;类型3：多次进出磁场&quot;">​</a></h3><p><strong>问题</strong>：粒子在多个磁场区域或同一边界多次反射</p><p><strong>解法</strong>:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>画出完整轨迹</span></span>
<span class="line"><span>利用对称性简化</span></span>
<span class="line"><span>总时间 = 各段时间之和</span></span></code></pre></div><hr><h2 id="套路总结图" tabindex="-1">套路总结图 <a class="header-anchor" href="#套路总结图" aria-label="Permalink to &quot;套路总结图&quot;">​</a></h2><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>磁场粒子问题</span></span>
<span class="line"><span>    │</span></span>
<span class="line"><span>    ├──→ 确定已知条件</span></span>
<span class="line"><span>    │       v、B、q、m、边界形状</span></span>
<span class="line"><span>    │</span></span>
<span class="line"><span>    ├──→ 计算半径</span></span>
<span class="line"><span>    │       r = mv/qB</span></span>
<span class="line"><span>    │</span></span>
<span class="line"><span>    ├──→ 画轨迹，找圆心</span></span>
<span class="line"><span>    │       速度垂线/弦垂直平分线</span></span>
<span class="line"><span>    │</span></span>
<span class="line"><span>    ├──→ 确定圆心角</span></span>
<span class="line"><span>    │       几何关系/偏转角</span></span>
<span class="line"><span>    │</span></span>
<span class="line"><span>    ├──→ 计算时间（如需）</span></span>
<span class="line"><span>    │       t = θm/qB</span></span>
<span class="line"><span>    │</span></span>
<span class="line"><span>    └──→ 求其他量</span></span>
<span class="line"><span>            磁场宽度、偏转距离、临界条件...</span></span></code></pre></div><hr><h2 id="常见陷阱" tabindex="-1">常见陷阱 <a class="header-anchor" href="#常见陷阱" aria-label="Permalink to &quot;常见陷阱&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:left;">陷阱</th><th style="text-align:left;">正确做法</th></tr></thead><tbody><tr><td style="text-align:left;">圆心找错</td><td style="text-align:left;">速度垂线必过圆心，不是速度延长线</td></tr><tr><td style="text-align:left;">圆心角与偏转角混淆</td><td style="text-align:left;">偏转角=圆心角，但要看清楚是哪个角</td></tr><tr><td style="text-align:left;">角度用度数计算</td><td style="text-align:left;">t = θm/qB中θ必须用弧度！</td></tr><tr><td style="text-align:left;">正负电荷轨迹搞反</td><td style="text-align:left;">负电荷受力方向与正电荷相反，用左手定则</td></tr><tr><td style="text-align:left;">忘记周期与速度无关</td><td style="text-align:left;">T = 2πm/qB，所有同种粒子周期相同</td></tr></tbody></table><hr><h2 id="快速检查清单" tabindex="-1">快速检查清单 <a class="header-anchor" href="#快速检查清单" aria-label="Permalink to &quot;快速检查清单&quot;">​</a></h2><ul><li>[ ] 用左手定则正确判断了偏转方向（正负电荷）</li><li>[ ] 正确计算了半径r = mv/qB</li><li>[ ] 圆心位置找对（速度垂线交点）</li><li>[ ] 圆心角与偏转角对应正确</li><li>[ ] 时间计算用了弧度制</li><li>[ ] 几何关系正确（弦长、半径、角度关系）</li></ul><hr><p><em>配套速查</em>: 速查卡 → 模型22<br><em>详细推导</em>: 【高一高二用】新课学习/详解/06-电磁学详解.md</p>`,79)])])}const u=s(p,[["render",l]]);export{g as __pageData,u as default};
